let allData = {{workflowparams:allData}}
const updatedRO = []
const saveAs = {{workflowparams:saveAs}}

for (const [index, roLineItem] of allData.table_repack.entries()) {

  roLineItem.organization_id = allData.organization_id;
  roLineItem.plant_id = allData.plant_id || null;
  roLineItem.line_index = index + 1;

  updatedRO.push(roLineItem)
}

allData.table_repack = updatedRO;

if ({{workflowparams:pageStatus}} === "Add") {
  allData.repack_status = "Draft";
}

if (saveAs === "Draft") {
  if (
    allData.repack_no_type !== -9999 &&
    (!allData.repack_no ||
      allData.repack_no === null ||
      allData.repack_no === "")
  ) {
    allData.repack_no = "draft";
  }
} else {
  if (
    allData.repack_no_type !== -9999 &&
    (!allData.repack_no ||
      allData.repack_no === null ||
      allData.repack_no === "" ||
      allData.repack_status !== "In Progress")
  ) {
    allData.repack_no = "issued";
  }
}

return {
  allData: allData,
  repack_status: allData.repack_status,
};

return {
  required_fields: JSON.stringify([
  { name: "repack_no", label: "Repack No" },
  { name: "repack_type", label: "Repack Type" },
  { name: "plant_id", label: "Plant" },
  {
    name: "table_repack",
    label: "Repacking Details",
    isArray: true,
    arrayType: "object",
    arrayFields: [],
  },
]),
  data: JSON.stringify({
    repack_no: {{node:code_node_M3uhXobN.data.allData.repack_no}},
    repack_type: {{node:code_node_M3uhXobN.data.allData.repack_type}},
    plant_id: {{node:code_node_M3uhXobN.data.allData.plant_id}},
    table_repack: {{node:code_node_M3uhXobN.data.allData.table_repack}}
  })
}

const repack_status = {{node:code_node_M3uhXobN.data.repack_status}} || "Draft";
const pageStatus = {{workflowparams:pageStatus}};

let roData = {{node:code_node_M3uhXobN.data.allData}} || {};
if (pageStatus === "Add") {
  const rawRoData = {{node:add_node_EA6zJ5gj.data}}
  roData = rawRoData[0]
  roData.table_repack = {{node:search_node_kL8C488c.data}}
} else if (pageStatus === "Edit" && repack_status !== "Draft") {
  roData = {{node:get_node_8Dk4sYit.data.data}}
} else if (pageStatus === "Edit" && repack_status === "Draft") {
  roData = {{node:get_node_UUNWojBU.data.data}}
}

return {
  allData: roData,
  tableData: roData.table_repack || [],
  processType: roData.repack_type || "",
}

const lineItem = {{node:loop_KN5pGSVB}};
const processType = {{node:code_node_nKKZe4ed.data.processType}};
const allData = {{node:code_node_nKKZe4ed.data.allData}};

const plantId = allData.plant_id || "";
const organizationId = allData.organization_id || "";
const repackNo = allData.repack_no || "";
const remark = lineItem.remarks || "";

// Parse staged data
let sourceHu = null;
try {
  sourceHu = lineItem.source_temp_data ? JSON.parse(lineItem.source_temp_data) : null;
} catch (e) { sourceHu = null; }

let targetHu = null;
try {
  targetHu = lineItem.target_temp_data ? JSON.parse(lineItem.target_temp_data) : null;
} catch (e) { targetHu = null; }

let itemsData = [];
try {
  itemsData = lineItem.items_temp_data ? JSON.parse(lineItem.items_temp_data) : [];
} catch (e) { itemsData = []; }

// Handle new target HU case: target_hu_id empty + target_hu_no = "Auto-generated number"
if ((processType === "Load" || processType === "Transfer") && !lineItem.target_hu_id && lineItem.target_hu_no === "Auto-generated number") {
  targetHu = targetHu || {};
  targetHu.id = "";
  targetHu.handling_no = "Auto-generated number";
  // Fill in the rest from row-level fields if targetHu parse was null
  targetHu.hu_material_id = targetHu.hu_material_id || "";
  targetHu.hu_type = targetHu.hu_type || "";
  targetHu.hu_quantity = targetHu.hu_quantity || 1;
  targetHu.hu_uom = targetHu.hu_uom || "";
  targetHu.storage_location_id = targetHu.storage_location_id || lineItem.target_storage_location || "";
  targetHu.location_id = targetHu.location_id || lineItem.target_hu_location || "";
}

// Build items array (REPACKING_PROCESS expects quantity, not unload_quantity)
const items = itemsData.map((it) => ({
  material_id: it.material_id,
  material_name: it.material_name,
  material_desc: it.material_desc,
  location_id: it.location_id,
  batch_id: it.batch_id || null,
  material_uom: it.material_uom,
  quantity: parseFloat(it.unload_quantity) || 0,
  balance_id: it.balance_id || "",
}));

return {
  plant_id: plantId,
  organization_id: organizationId,
  trx_no: repackNo,
  transaction_type: "RO",
  process_type: processType,
  items,
  source_hu: sourceHu,
  target_hu: targetHu,
  target_location_id: lineItem.target_location || "",
  target_storage_location_id: lineItem.target_storage_location || "",
  remark,
};
